// ===============================
// 1. Grundlagen
// ===============================
const cleanedStory = $input.first().json.cleanedStory
  .replace(/STORY_BEGIN/g, '')
  .replace(/STORY_END/g, '')
  .trim();


const rawOutput = $input.first().json.rawOutput;

const webhookBody = $('Webhook').first().json.body;
const previousGameState = webhookBody.gameState ?? {};

// ===============================
// 2. STATE_UPDATE extrahieren (optional)
// ===============================
let gameStateUpdate = null;

if (rawOutput && rawOutput.includes('===STATE_UPDATE===')) {
  const stateRaw = rawOutput.split('===STATE_UPDATE===')[1]?.trim();

  if (!stateRaw) {
    throw new Error('вќЊ STATE_UPDATE Trennzeile vorhanden, aber kein JSON');
  }

  try {
    gameStateUpdate = JSON.parse(stateRaw);
  } catch {
    throw new Error('вќЊ STATE_UPDATE ist kein valides JSON');
  }
}

// ===============================
// 3. Hilfsfunktion: Deep Merge (Delta)
// ===============================
function deepMerge(target, source) {
  if (!source) return target;

  for (const key of Object.keys(source)) {
    if (
      source[key] &&
      typeof source[key] === 'object' &&
      !Array.isArray(source[key])
    ) {
      target[key] = deepMerge(target[key] ?? {}, source[key]);
    } else {
      target[key] = source[key];
    }
  }
  return target;
}

// ===============================
// 4. GameState aus Delta bauen
// ===============================
let mergedGameState = JSON.parse(JSON.stringify(previousGameState));

if (gameStateUpdate) {
  // Character-Delta
  if (gameStateUpdate.character) {
    mergedGameState.character = deepMerge(
      mergedGameState.character ?? {},
      gameStateUpdate.character
    );
    mergedGameState.character.id = previousGameState.character?.id;
  }

  // GameSession-Delta
  if (gameStateUpdate.gameSession) {
    mergedGameState.gameSession = deepMerge(
      mergedGameState.gameSession ?? {},
      gameStateUpdate.gameSession
    );
    mergedGameState.gameSession.id = previousGameState.gameSession?.id;
  }

  // Enemy-Delta (KORREKT)
  if ('currentEnemy' in gameStateUpdate) {
    if (gameStateUpdate.currentEnemy === null) {
      mergedGameState.currentEnemy = null;
    } else {
      mergedGameState.currentEnemy = deepMerge(
        mergedGameState.currentEnemy ?? {},
        gameStateUpdate.currentEnemy
      );
    }
  }
}

// ===============================
// 5. Finales RГјckgabeobjekt
// ===============================
return {
  response: cleanedStory,

  characterId: webhookBody.characterId,
  gameSessionId: webhookBody.gameSessionId,

  gameState: mergedGameState,

  actionsPerformed: gameStateUpdate?.actionsPerformed ?? []
};

const raw = $input.first().json.output;

// 1пёЏвѓЈ Tool-Leaks am Anfang entfernen
let sanitized = raw.replace(/^\s*\[.*?\]\s*/s, '');

// 2пёЏвѓЈ Story extrahieren
let cleanedStory = '';
const storyMatch = sanitized.match(/STORY_BEGIN([\s\S]*?)STORY_END/);

if (storyMatch) {
  cleanedStory = storyMatch[1].trim();
} else {
  cleanedStory = sanitized.split('===STATE_UPDATE===')[0].trim();
}

// 3пёЏвѓЈ Markdown entfernen (Sternchen & Unterstriche)
cleanedStory = cleanedStory
  // **fett** oder *kursiv*
  .replace(/\*\*(.*?)\*\*/g, '$1')
  .replace(/\*(.*?)\*/g, '$1')
  // __unterstrichen__ oder _kursiv_
  .replace(/__(.*?)__/g, '$1')
  .replace(/_(.*?)_/g, '$1');

// 4пёЏвѓЈ Notbremse: Story darf kein JSON sein
if (cleanedStory.startsWith('{') || cleanedStory.startsWith('[')) {
  cleanedStory =
    'Zorro knurrt leise. Die Magie flackert вЂ“ erzГ¤hle weiter, Held.';
}

return {
  cleanedStory,
  rawOutput: sanitized
};
